"""
MKT Original Language Commentary — Psalms chapters 1–8
Run: python3 scripts/zc-original-psalms-1-8.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/psalms.json (MKT text)

Key decisions in this range:
- Ps 1:1 ʾashrê: "Blessed" renders the plural ʾashrê (not bārûk/bĕrākāh); the
  exclamatory formula "O the blessedness of..." is preserved in MKT "Blessed."
- Ps 1:2 tôrāh: MKT "instruction" (not "law") follows the broader Hebrew sense of
  tôrāh as teaching/direction rather than legal code alone.
- Ps 2:7 yĕlidtîkā: "I have begotten you" — perfect aspect (completed act); MKT
  preserves the Hebrew tense rather than rendering it as a present statement.
- Ps 2:12 bar: MKT follows the MT reading of bar as "Son" (Aramaic), an unusual
  word in a Hebrew psalm. The LXX reads παιδείας ("instruction").
- Ps 4:4 rigzû: cited in Eph 4:26 as "be angry"; MKT "tremble with awe" follows
  the dominant Hebrew semantic range (physical shaking/trembling) rather than anger.
- Ps 5:9 qibrām gerônām: "open grave" image for the throat — MKT preserves the
  full force of this death-speech metaphor.
- Ps 6:1 yākhaḥ (tôkîḥ): legal connotation — "reprove/convict in court"; MKT
  "rebuke" captures the force though loses the forensic register.
- Ps 7:1 shiggāyôn: transliterated in MKT heading; likely a passionate/irregular
  lyric form; not well understood.
- Ps 8:2 ʿōz: MKT "ordained praise" follows LXX (αἶνον) and Matt 21:16; the
  Hebrew ʿōz can mean "strength/fortress" — the LXX makes an interpretive choice.
- Ps 8:5 ʾĕlōhîm: MKT "heavenly beings" follows LXX ἀγγέλους and Heb 2:7; the
  Hebrew is genuinely ambiguous (God / divine beings / angels).
- Verses Ps 2:7 and Ps 8:4 were already present; script skips them via merge_comm.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original commentary for Psalms 1–8 — the Psalter's gateway poems covering
#   the two-ways theology (Ps 1), the royal Messiah (Ps 2), lament and trust (Ps 3–7),
#   and the crown-of-creation theology (Ps 8). Key lexical focus: ʾashrê vs bārûk,
#   tôrāh as instruction/direction, the shiggāyôn genre, and the ʾĕlōhîm ambiguity of Ps 8:5.
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(1,9)])" should show 6,11,8,8,12,10,17,9.

PSALMS = {
  "1": {
    "1": '<p><strong>אַשְׁרֵי</strong> (<em>ʾashrê</em>) — "Blessed" opens the Psalter but the Hebrew is not <em>bārûk</em> (the word for formal blessing, as in "blessed be God"). <em>ʾAshrê</em> is a plural construct meaning "the blessednesses of" or "O the felicity of!" — an exclamation about a person\'s flourishing state, not a pronouncement of blessing over them. The Beatitudes of Matthew 5 use this form (μακάριος in the LXX).</p><p>The three-part movement — not walking in the counsel of the wicked, not standing in the way of sinners, not sitting in the seat of scoffers — traces a progressive entrenchment: the wicked begin as advisers, become companions on the same road, and finally become the community one settles in. The syntax moves from walking to standing to sitting, each stage more settled.</p>',
    "2": '<p><strong>תּוֹרָה</strong> (<em>tôrāh</em>, "instruction") — the MKT uses "instruction" rather than "law" to capture the Hebrew root <em>yārāh</em> (to shoot/point/direct). Torah is not primarily a legal code but a body of teaching that orients the life. The Psalter opens by depicting the righteous person as one who finds their delight (<em>ḥāpēṣ</em>) in this directing word.</p><p><strong>יֶהְגֶּה</strong> (<em>yehgeh</em>, "meditates") is from <em>hāgāh</em>, the same word used for the growling of a lion (Isa 31:4) and the cooing of a dove (Isa 38:14). It is not silent, abstract reflection but oral, murmuring recitation — the physical act of speaking the words under the breath "day and night." Ancient reading was always oral.</p>',
    "3": '<p><strong>שָׁתוּל</strong> (<em>shātûl</em>, "planted") is not random growth but deliberate transplanting — the word implies an intentional hand placing the tree beside the water source. <strong>פַּלְגֵי מַיִם</strong> (<em>palgê māyim</em>, "streams of water") are not a natural river but irrigation channels — human-made conduits bringing water to where it is placed. The image is of a life deliberately situated near a sustained supply, not accidental proximity.</p><p>"Its leaf does not wither" (<em>לֹא-יִבּוֹל עָלֵהוּ</em>) — the contrast is not only with the wicked (v4) but with a tree away from water, where even in summer the leaves hold. The <em>fruitful in its season</em> phrase (<em>פִּרְיוֹ יִתֵּן בְּעִתּוֹ</em>) implies that faithfulness is not always immediately visible but yields at the appointed time.</p>',
    "4": '<p><strong>כַּמֹּץ</strong> (<em>kammōts</em>, "like chaff") — the contrast between the rooted tree (v3) and chaff is total: the tree has roots, location, moisture, and fruit; chaff (<em>môts</em>) is the husk of grain winnowed out, weightless, rootless, and of no nutritional value. The wind does not destroy it so much as reveal what it always was. The judgment of the wicked (v5) is not punishment added from outside but exposure of what is already the case.</p>',
    "5": '<p><strong>בַּקָּהָל</strong> (<em>baqqāhāl</em>, "in the assembly") — <em>qāhāl</em> is the formal covenant assembly, not just any gathering. The wicked will not "stand" (<em>יָקֻמוּ</em>) in it — the verb is the same as "stand" in the court, suggesting judicial standing. They will not have standing in the assembly of the righteous because they have no ground to stand on — chaff has no weight.</p>',
    "6": '<p><strong>יוֹדֵעַ</strong> (<em>yôdēaʿ</em>, "watches over") — the MKT renders "the LORD watches over the way of the righteous," but the Hebrew is literally "the LORD <em>knows</em> the way of the righteous." Knowledge here is relational, not merely informational — the same <em>yāḏaʿ</em> used for intimate knowing (Gen 4:1). The LORD has a knowing relationship with the path the righteous walk. The way of the wicked "will perish" (<em>תֹּאבֵד</em>) — imperfect: it is in the process of perishing, heading toward destruction, even now.</p>',
  },
  "2": {
    "1": '<p><strong>לָמָּה רָגְשׁוּ גוֹיִם</strong> (<em>lāmmāh rāgĕshû gôyim</em>) — "why do the nations rage?" The verb <em>rāgash</em> (to be in tumult, to throng/conspire) occurs only here in the Hebrew Bible outside of this form; the LXX translates ἐφρύαξαν (to be insolent/neigh like horses). The word suggests uncontrolled, agitated motion — the nations in restless, futile commotion. Acts 4:25 cites this verse at the Jerusalem church\'s prayer after the arrest of Peter and John, identifying the "nations" with Herod, Pilate, Gentiles, and the people of Israel.</p><p><strong>רִיק</strong> (<em>rîq</em>, "in vain") — the peoples plot <em>rîq</em>: emptiness, futility. The futility is built into the conspiracy from the beginning; not that it fails but that it is empty of substance.</p>',
    "2": '<p><strong>מְשִׁיחוֹ</strong> (<em>mĕshîḥô</em>, "his Anointed One") — from <em>māshaḥ</em>, to anoint with oil. The word appears here in the context of the Davidic king on whom the LORD\'s oil was poured. "His Anointed" is the one who belongs to the LORD by virtue of anointing — the divine claim on the person. The conspiracy is therefore not against a human king but against the one who has been set apart by God.</p>',
    "3": '<p><strong>מוֹסְרוֹתֵימוֹ</strong> (<em>môsĕrôtêmô</em>, "their bonds") and <strong>עֲבֹתֵימוֹ</strong> (<em>ʿăbōtêmô</em>, "their cords") — the rebels\' self-understanding: they experience divine sovereignty as constraint. The cords (<em>ʿăbōt</em>) can also mean "ropes" used to bind animals — they picture themselves as livestock under a yoke. The irony is that what they call bonds are the ordering structures that make flourishing possible.</p>',
    "4": '<p><strong>יִשְׂחַק</strong> (<em>yisḥāq</em>, "laughs") — the divine response to the conspiracy is not panic but laughter. The same root as the name Isaac (<em>yitsḥāq</em>), from <em>ṣāḥaq</em> — to laugh, to play. The LORD who sits enthroned in the heavens finds the nations\' plots incongruous with reality. <strong>יִלְעַג</strong> (<em>yilʿag</em>, "scoffs") — to mock, to stammer in imitation; the LORD\'s scoffing is not contemptuous anger but the amusement of absolute security.</p>',
    "5": '<p><strong>בְּאַפּוֹ</strong> (<em>bĕʾappô</em>, "in his wrath") and <strong>בַחֲרוֹן אַפּוֹ</strong> (<em>baḥărôn ʾappô</em>, "in his burning anger") — <em>ʾap</em> literally means "nostril/nose"; anger in Hebrew is conceived as snorting/fuming breath. <em>Ḥărôn</em> (burning, from <em>ḥārāh</em>, to burn) intensifies it: not merely irritation but heated wrath. The divine speech that follows (v6) is the decree that settles the matter.</p>',
    "6": '<p><strong>נָסַכְתִּי</strong> (<em>nāsaktî</em>, "I have installed") — the verb <em>nāsak</em> typically means to pour out (as a libation) or to cast metal; in this context it means "to set in place" as one sets a foundation stone. The perfect tense (<em>nāsaktî</em>) declares a completed act: the installation of the King is already done. Zion as <strong>הַר-קָדְשִׁי</strong> (<em>har qodshî</em>, "my holy hill") designates the place as consecrated territory belonging to the LORD.</p>',
    "8": '<p><strong>שְׁאַל מִמֶּנִּי</strong> (<em>shĕʾal mimmennî</em>, "ask of me") — the imperative of <em>shāʾal</em>: the invitation to request. The Anointed One is invited to ask for his inheritance — the nations and the ends of the earth. The inheritance motif connects to the Abrahamic promise (Gen 17:6) and the Davidic covenant (2 Sam 7:12-16). The gift is cosmic in scope: <strong>אַפְסֵי-אָרֶץ</strong> (<em>ʾapsê-ʾāreṣ</em>) — the "ends/limits of the earth," the outermost extremities.</p>',
    "9": '<p><strong>תְּרֹעֵם בְּשֵׁבֶט בַּרְזֶל</strong> (<em>tĕrōʿēm bĕshêbet barzel</em>, "you shall rule them with an iron rod") — <em>shêbet</em> is both "rod/staff" (the shepherd\'s implement) and the scepter of authority. Iron makes it a weapon of force rather than a pastoral tool. <strong>תְּנַפְּצֵם</strong> (<em>tĕnappĕṣêm</em>, "shatter them") — piel of <em>nāpaṣ</em>: to smash into pieces, used of breaking pottery (Jer 19:11). This verse is cited three times in Revelation (2:27; 12:5; 19:15) as the authority given to the risen Christ and shared with those who overcome.</p>',
    "10": '<p><strong>הַשְׂכִּילוּ</strong> (<em>haśkîlû</em>, "be wise") — hiphil imperative of <em>śākal</em>: not merely "be intelligent" but "act with insight/prudence" — wisdom that produces right action. The address turns from narrative to direct exhortation. <strong>הִוָּסְרוּ</strong> (<em>hiwwāsĕrû</em>, "take warning") — niphal of <em>yāsar</em>: receive instruction/discipline; the word is often used for parental or divine discipline.</p>',
    "11": '<p><strong>עִבְדוּ אֶת-יְהוָה בְּיִרְאָה</strong> (<em>ʿibdû ʾet-YHWH bĕyirʾāh</em>, "serve the LORD with reverent fear") — <em>ʿābad</em> (serve/work) can refer to labor, worship, and service simultaneously; the kings are called to re-orient their service from self-appointed dominion to submission to the LORD. <strong>גִּילוּ בִּרְעָדָה</strong> (<em>gîlû birʿādāh</em>, "celebrate with trembling") — <em>gîl</em> is exultation, a word for intense, even physical, joy; <em>rĕʿādāh</em> is shaking, trembling. The pairing is paradoxical: joyful trembling, not joyless fear. Paul echoes this: "work out your salvation with fear and trembling" (Phil 2:12).</p>',
    "12": '<p><strong>בַּר</strong> (<em>bar</em>, "Son") — an Aramaic word (not the Hebrew <em>ben</em>) appearing in this Hebrew poem; its rarity has made it a textual puzzle. The MT is supported by many manuscripts as bar ("son"), giving "pay homage to the Son." The LXX takes a different path (δράξασθε παιδείας, "embrace discipline"), suggesting the Greek translators read differently or interpreted the difficult term. The MKT follows MT. The psalm ends on the same note as it began: <strong>אַשְׁרֵי</strong> (<em>ʾashrê</em>) — "Blessed" — forming an <em>inclusio</em> with Psalm 1:1: the blessed life belongs to those who take refuge in the Son.</p>',
  },
  "3": {
    "1": '<p><strong>מִזְמוֹר לְדָוִד</strong> (<em>mizmôr lĕdāwid</em>, "A Psalm of David") — <em>mizmôr</em> is from <em>zāmar</em> (to sing with string accompaniment, to pluck/play), not a generic word for poem. It specifically indicates a song meant for instruments. The superscription situates the psalm in the aftermath of Absalom\'s rebellion (2 Sam 15-18), giving the corporate lament an autobiographical anchor.</p><p><strong>רַבּוּ צָרָי</strong> (<em>rabbû ṣārāy</em>, "how many are my foes!") — the opening exclamation without a particle: the proliferation of enemies is not calmly observed but blurted out. <em>Ṣārāy</em> (my adversaries) from <em>ṣārar</em>: to press tight, bind, besiege — not casual opponents but those who press hard against him.</p>',
    "2": '<p><strong>אֵין יְשׁוּעָתָה לּוֹ בֵאלֹהִים</strong> (<em>ʾên yĕshûʿātāh llô bēlōhîm</em>, "there is no salvation for him in God") — the enemies\' taunt is theological: they claim that even God is not able or willing to rescue. The final particle <em>selāh</em> (סֶלָה) appears here for the first time in the Psalter; its precise meaning is uncertain (a musical interlude? a pause for reflection? from <em>sālal</em>, to lift up), but it marks a break after which the Psalmist turns to address God directly.</p>',
    "3": '<p><strong>מָגֵן בַּעֲדִי</strong> (<em>māgên baʿădî</em>, "a shield around me") — <em>māgên</em> is the small handheld shield (vs. <em>ṣinnāh</em>, the full-body shield of Ps 5:12). God as personal protection surrounding the Psalmist on all sides (<em>baʿădî</em> = "about me/on my behalf"). <strong>מֵרִים רֹאשִׁי</strong> (<em>mêrîm rōʾshî</em>, "the one who lifts my head") — the participle indicates ongoing action: God is continuously the one lifting the head, a gesture of honor, dignity, and courage in contrast to the enemies\' contempt.</p>',
    "4": '<p><strong>קוֹלִי אֶל-יְהוָה אֶקְרָא</strong> (<em>qôlî ʾel-YHWH ʾeqrāʾ</em>, "I cried out to the LORD") — the imperfect (<em>ʾeqrāʾ</em>) here functions as a future-historical narration: "I will call/I called." <strong>מֵהַר קָדְשׁוֹ</strong> (<em>mêhar qodshô</em>, "from his holy hill") — the answer comes from Zion, the place of the divine dwelling, reinforcing that the LORD who installs the King (Ps 2:6) also hears from that same place.</p>',
    "5": '<p><strong>שָׁכַבְתִּי וָאִישָׁנָה</strong> (<em>shākabetî wāʾîshānāh</em>, "I lay down and slept") — both verbs are in the perfect (completed action): David actually slept. The waw-consecutive pattern (<em>wāʾîshānāh</em>) presents the actions as sequential narrative. In the middle of violent crisis — enemies surrounding him — he slept. <strong>הֱקִיצוֹתִי</strong> (<em>hĕqîṣôtî</em>, "I awoke") — the act of waking is attributed to divine sustaining: "the LORD sustained me." Sleep and waking alike are acts of trust, not statements of invulnerability.</p>',
    "6": '<p><strong>לֹא-אִירָא</strong> (<em>lōʾ-ʾîrāʾ</em>, "I will not fear") — imperfect negated: ongoing, habitual non-fear. The tens of thousands (<em>רִבְבוֹת</em>, <em>rĕbābôt</em>) surrounding on every side (<em>שָׁתוּ עָלַי סָבִיב</em>) represent the most extreme situation imaginable — total encirclement by vast numbers. The confidence of v5-6 flows from the fact of v4: God heard and answered.</p>',
    "7": '<p><strong>קוּמָה יְהוָה</strong> (<em>qûmāh YHWH</em>, "Rise up, O LORD!") — the imperative <em>qûmāh</em> is an urgent call; the cohortative form adds emotional intensity. The archaic battle cry echoes Num 10:35 (the ark-procession cry: "Rise up, O LORD!"). <strong>שִׁבַּרְתָּ</strong> (<em>shibbartā</em>, "you shatter") — the perfect of confidence: not a future hope but a declaration of what God does, treating the anticipated rescue as accomplished. The jaw/teeth imagery (<em>לֶחִי</em>, cheek; <em>שִׁנֵּי</em>, teeth) disables the enemy\'s capacity to wound.</p>',
    "8": '<p><strong>לַיהוָה הַיְשׁוּעָה</strong> (<em>laYHWH hayyĕshûʿāh</em>, "Salvation belongs to the LORD") — the noun with the definite article: <em>the</em> salvation, not a salvation. It is a possession of the LORD, not a human achievement or political strategy. This declaration closes the psalm as a theological assertion: whatever the enemies say (v2), they are wrong. <em>Selāh</em> closes the psalm as it marked the crisis of v2.</p>',
  },
  "4": {
    "1": '<p><strong>אֱלֹהֵי צִדְקִי</strong> (<em>ʾĕlōhê ṣidqî</em>, "God of my righteousness") — not "my righteous God" (which would be <em>ʾĕlōhay haṣṣaddîq</em>) but "the God who is the source/vindicator of my righteousness." <em>Ṣedeq</em>/<em>ṣĕdāqāh</em> (righteousness) here has a forensic sense: vindication, the declaration that one\'s cause is just. God is appealed to as the one who will adjudicate David\'s case.</p><p><strong>בַּצָּר הִרְחַבְתָּ לִּי</strong> (<em>baṣṣār hirḥabtā llî</em>, "you freed me when I was in distress") — literally "in the tight place you enlarged me." <em>Ṣār</em> (distress) and <em>rāḥab</em> (wide/broad) are antonyms: God takes the person from constriction to wide-open space. The spatial metaphor of salvation as expansion is common in the Psalms.</p>',
    "2": '<p><strong>בְּנֵי אִישׁ</strong> (<em>bĕnê ʾîsh</em>, "O men") — literally "sons of man" using <em>ʾîsh</em> (distinguished man, man of rank), not <em>ʾādām</em> (common humanity). The address is to the distinguished and influential, those who should know better. <strong>כָּזָב</strong> (<em>kāzāb</em>, "lies") — falsehood, deception; the accusers are those who "love what is worthless (<em>rîq</em>) and pursue lies." <em>Rîq</em> appears again from Ps 2:1 — the futile, empty plotting.</p>',
    "3": '<p><strong>הִפְלָה יְהוָה חָסִיד לוֹ</strong> (<em>hiphlāh YHWH ḥāsîd lô</em>, "the LORD has set apart the faithful for himself") — <em>hiphlāh</em> (hiphil of <em>pālāh</em>): to make distinct, to set apart as remarkable or special. The <em>ḥāsîd</em> (faithful/godly one) is the one characterized by <em>ḥesed</em> (covenant loyalty) — not merely religious but relationally faithful to the covenant. The LORD has specially distinguished this person as his own.</p>',
    "4": '<p><strong>רִגְזוּ וְאַל-תֶּחֱטָאוּ</strong> (<em>rigzû wĕʾal-teḥĕṭāʾû</em>, "Tremble with awe and do not sin") — Paul cites this in Eph 4:26 ("be angry but do not sin"), and the LXX translates it ὀργίζεσθε καὶ μὴ ἁμαρτάνετε. The Hebrew <em>rāgaz</em> primarily means to tremble/shake (used of earthquakes and of the earth\'s response to the divine presence); its translation as "anger" may import a secondary meaning. The MKT "tremble with awe" recovers the primary sense: physical trembling in response to God\'s reality.</p><p><strong>אִמְרוּ בִלְבַבְכֶם</strong> (<em>ʾimrû bilbabkem</em>, "search your hearts") — literally "say in your hearts." The heart (<em>lēbāb</em>) is the organ of thought, will, and intention in Hebrew anthropology — not primarily emotion but cognition and decision. On your beds (<em>מִשְׁכְּבוֹתֵיכֶם</em>), in silence (<em>וְדֹמּוּ</em>, from <em>dāmam</em>: to be still/silent).</p>',
    "5": '<p><strong>זִבְחוּ זִבְחֵי-צֶדֶק</strong> (<em>zibḥû zibḥê-ṣedeq</em>, "Offer right sacrifices") — literally "sacrifices of righteousness," using <em>ṣedeq</em> as a genitive of quality: sacrifices characterized by rightness. Not merely technically correct ritual but offering from a right internal orientation. The instruction parallels Ps 51:17-19 where David learns that God does not desire sacrifice per se but a broken and contrite heart.</p>',
    "6": '<p><strong>נְסָה-עָלֵינוּ אוֹר פָּנֶיךָ</strong> (<em>nĕsāh-ʿālênû ʾôr pānêkā</em>, "Let the light of your face shine on us") — the verb <em>nāsāh</em> (to lift up, to display) and the phrase <em>ʾôr pānêkā</em> (light of your face) both come from the Aaronic blessing (Num 6:25: "The LORD make his face shine on you"). The communal prayer invokes the priestly blessing pattern: the turned and shining face of God is the answer to the question "who will show us any good?"</p>',
    "7": '<p><strong>נָתַתָּה שִׂמְחָה בְלִבִּי</strong> (<em>nātattāh śimḥāh bĕlibbî</em>, "You have placed more joy in my heart") — the joy is given (<em>nātan</em>, perfect: completed gift). It is not self-generated. The comparison is explicit: more than "when their grain and wine overflow" (<em>מֵעֵת דְּגָנָם וְתִירוֹשָׁם רָבּוּ</em>). The joy of the harvest (the maximum moment of agrarian celebration) is less than the joy God places internally. The external <em>versus</em> internal contrast is sharp.</p>',
    "8": '<p><strong>בְּשָׁלוֹם יַחְדָּו אֶשְׁכְּבָה וְאִישָׁן</strong> (<em>bĕshālôm yaḥdāw ʾeshkĕbāh wĕʾîshān</em>, "In peace I will lie down and sleep") — <em>shālôm</em> (completeness/peace) as the condition of sleep: rest that is whole, not anxious. <em>Yaḥdāw</em> (together/at once) intensifies: simultaneously, without delay. <strong>לְבַדָד</strong> (<em>lĕbaddō</em>, "you alone") — not divine plurality but exclusive reliance: "you, you alone, O LORD, cause me to dwell in safety." The security is not social, political, or personal — only divine.</p>',
  },
  "5": {
    "1": '<p><strong>אֲמָרַי</strong> (<em>ʾamāray</em>, "my words") and <strong>הֲגִיגִי</strong> (<em>hăgîgî</em>, "my groaning") — two distinct levels of speech. <em>ʾImrāh</em> (words, utterances) refers to articulated speech; <em>hăgîg</em> (from <em>hāgāh</em>) is the inarticulate murmuring of Ps 1:2, the inward meditation that may be pre-verbal. Both are addressed to the LORD: the fully-formed words and the groan that underlies them. The superscription "for the flutes" (<em>הַנְּחִילוֹת</em>, <em>hanĕḥîlôt</em>) is uncertain — possibly meaning "for wind instruments" or referring to a tune.</p>',
    "2": '<p><strong>מַלְכִּי וֵאלֹהַי</strong> (<em>malkî wēʾlōhay</em>, "my King and my God") — the double vocative places God in the role of sovereign ruler whom the Psalmist approaches as a subject approaching the throne. The prayer is a royal petition, not merely a private devotion. <em>ʾElōhay</em> (my God) with the first-person suffix: personal relationship, not generic deity.</p>',
    "3": '<p><strong>בֹּקֶר תִּשְׁמַע קוֹלִי</strong> (<em>bōqer tishmaʿ qôlî</em>, "in the morning you hear my voice") — the morning is the time of the daily sacrifice and the moment when petitions were heard. <strong>אֲעָרְכָה-לְּךָ</strong> (<em>ʾăʿārkāh-llĕkā</em>, "I lay my prayer before you") — <em>ʿārak</em>: to arrange in order, to set in array (as a battle formation or an offering laid out). Prayer as deliberate, ordered presentation — not random petition but careful placement. <strong>אֲצַפֶּה</strong> (<em>ʾăṣappeh</em>, "and wait") — <em>ṣāpāh</em>: to watch/look out (as a watchman on a wall). Prayer followed by watchful waiting for the answer.</p>',
    "4": '<p><strong>לֹא אֵל-חָפֵץ רֶשַׁע אָתָּה</strong> (<em>lōʾ ʾêl-ḥāpēṣ reshaʿ ʾāttāh</em>, "you are not a God who takes pleasure in wickedness") — the logic of prayer: the God addressed is one whose character makes wickedness alien. <em>Ḥāpēṣ</em> (to delight in/desire) — not mere neutral toleration but active delight; God has no such delight in <em>reshaʿ</em> (wickedness — the condition of being fundamentally wrong/twisted). <em>יָגֻר</em> (<em>yāgur</em>, "cannot dwell") from <em>gûr</em>: to sojourn, to lodge as a guest. Evil cannot even temporarily reside with God.</p>',
    "5": '<p><strong>לֹא-יִתְיַצְּבוּ הוֹלְלִים</strong> (<em>lōʾ-yityaṣṣĕbû hôlĕlîm</em>, "the arrogant cannot stand in your sight") — <em>hôlĕlîm</em> (from <em>hālal</em>, root of Hallelujah): here in a negative sense, those who are boastful, bragging fools. They "cannot stand" (<em>yityaṣṣĕbû</em>, hithpael of <em>nāṣab</em>: to take one\'s stand, to present oneself) — judicial language: they have no standing to appear before this God. <strong>שָׂנֵאתָ</strong> (<em>śānêʾtā</em>, "you hate") — the perfect of established, settled disposition: not a momentary emotion but a stable orientation of God against evil-workers.</p>',
    "6": '<p><strong>תְּאַבֵּד דֹּבְרֵי כָזָב</strong> (<em>tĕʾabbêd dōbĕrê kāzāb</em>, "you destroy those who speak falsehood") — <em>ʾābad</em> (piel): to cause to perish, to destroy utterly. The specific evil targeted is speech: false testimony, lies. <strong>תְּעֵב יְהוָה</strong> (<em>tĕʿêb YHWH</em>, "the LORD abhors") — <em>tāʿab</em>: to abhor, to find detestable (used of the ritual abomination of idols and the moral abomination of injustice). The <em>ʾîsh-dāmîm</em> (man of bloodshed) and the <em>mirmāh</em> (deceitful) man are equally objects of divine abhorrence.</p>',
    "7": '<p><strong>בְּרֹב חַסְדְּךָ</strong> (<em>bĕrōb ḥasdĕkā</em>, "through the abundance of your steadfast love") — <em>ḥesed</em> (covenant loyalty, steadfast love) is the ground of access. Not merit but <em>ḥesed</em> opens the way in. <strong>אֶשְׁתַּחֲוֶה</strong> (<em>ʾeshtaḥăweh</em>, "I will bow down") — hithpael of <em>shāḥāh</em>: the full prostration of reverence. The Psalmist who enters by grace bows in reverence — access through <em>ḥesed</em> does not reduce the awe of presence.</p>',
    "8": '<p><strong>הוֹרֵנִי יְהוָה דַּרְכֶּךָ</strong> (<em>hôrênî YHWH darkkekā</em>, "lead me, O LORD, in your righteousness") — hiphil imperative of <em>yārāh</em>, the same root as <em>tôrāh</em>: "teach me/point me/direct me." The prayer for divine direction uses the word from which Torah gets its meaning. <strong>לְמַעַן שׁוֹרְרָי</strong> (<em>lĕmaʿan shôrĕrāy</em>, "because of those who lie in wait for me") — <em>shōrĕr</em> is from the root meaning to watch/observe with hostile intent. Those who spy on the Psalmist create the urgency for divine guiding — without it, he will walk into their traps.</p>',
    "9": '<p><strong>קִבְרָם גְּרוֹנָם</strong> (<em>qibrām gerônām</em>, "their throat is an open grave") — one of the most striking images in the Psalter: the speech coming out of the enemy\'s throat has the quality of an open tomb — the stench of death and corruption. <em>Qeber</em> (grave) and <em>gārôn</em> (throat/neck) are in a construct chain: their throat is a-grave-of-them, a grave that belongs to and characterizes them. Paul cites this in Romans 3:13 as part of his catena of OT verses demonstrating universal human sinfulness. <strong>חֲלַק</strong> (<em>ḥālāq</em>, "flatter") — to make smooth; their tongues are smooth/slippery — the polished, dangerous speech of flattery that conceals hostile intent.</p>',
    "10": '<p><strong>הַאֲשִׁימֵם אֱלֹהִים</strong> (<em>haʾăshîmêm ʾĕlōhîm</em>, "Hold them guilty, O God") — hiphil of <em>ʾāsham</em>: to declare guilty, to cause to bear their own guilt. This is an <em>imprecatory</em> element — the Psalmist calls on God to bring justice on the wicked. The grounds are explicit: "for their many rebellions (<em>פִּשְׁעֵיהֶם</em>, <em>pishʿêhem</em>)" and "for they have defied you (<em>מָרוּ בָךְ</em>)." The judgment called for is not personal revenge but divine justice against covenant-breaking rebellion.</p>',
    "11": '<p><strong>יִשְׂמְחוּ כָל-חוֹסֵי בָךְ</strong> (<em>yismĕḥû kol-ḥôsê vāk</em>, "let all who take refuge in you rejoice") — <em>ḥāsāh</em> (to take refuge) is one of the key Psalmic words for trust — running to God for shelter as one runs to a fortress. The call to joy (<em>śāmaḥ</em>) and shout (<em>rānan</em>) is grounded in the security of refuge, not the absence of enemies. <strong>תָּסֵךְ עָלֵימוֹ</strong> (<em>tāsêk ʿālêmô</em>, "spread your protection") — <em>sākak</em>: to cover over, to provide shelter; the canopy of divine protection.</p>',
    "12": '<p><strong>כַּצִּנָּה רָצוֹן תַּעְטְרֶנּוּ</strong> (<em>kaṣṣinnāh rāṣôn taʿṭĕrennû</em>, "you surround him with favor as with a shield") — <em>ṣinnāh</em> is the large body-shield (contrast <em>māgên</em> of Ps 3:3) — the shield that covers the whole person. <em>Rāṣôn</em> (favor, goodwill, delight) surrounds the righteous as a shield surrounds a soldier: divine favor is the outer layer protecting the one who trusts. The psalm ends by answering its opening: the one who prays in the morning (v3) is the one whom God shields.</p>',
  },
  "6": {
    "1": '<p><strong>שְׁמִינִית</strong> (<em>shĕmînît</em>, "Sheminith") — literally "eighth"; a musical term appearing also in Ps 12:1. Its precise meaning is uncertain — possibly an eight-stringed instrument, a particular musical mode, or a pitch register (Sheminith may indicate a low-pitched performance, contrasted with ʿalāmôt in Ps 46:1). <strong>אַל-בְּאַפְּךָ תוֹכִיחֵנִי</strong> (<em>ʾal-bĕʾappĕkā tôkîḥênî</em>, "do not rebuke me in your anger") — <em>yākhaḥ</em> (hiphil <em>tôkîaḥ</em>) is a legal term: to argue a case, to convict, to bring a charge. The Psalmist is not asking God to be kind instead of strict, but to not prosecute him in anger. The same plea appears in Ps 38:1. The fear is not of discipline per se but of the full force of divine judicial wrath.</p>',
    "2": '<p><strong>חָנֵּנִי יְהוָה כִּי אֻמְלַל אָנִי</strong> (<em>ḥonnênî YHWH kî ʾumlal ʾānî</em>, "Be gracious to me, O LORD, for I am weak") — <em>ḥānan</em>: to be gracious, to show mercy, to give something not deserved. <em>ʾUmlal</em> (pual of <em>ʾāmal</em>): weak, languishing, withered — a passive form suggesting a state being done to him, not chosen. <strong>עֲצָמַי נִבְהָלוּ</strong> (<em>ʿăṣāmay nibhālû</em>, "my bones are in agony") — <em>nābhal</em> (niphal): to be dismayed, to be terrified — bones as the deepest physical structure of the person are shaken to the core. Ancient medicine located the deepest vitality in the bones.</p>',
    "3": '<p><strong>נַפְשִׁי נִבְהֲלָה מְאֹד</strong> (<em>napshî nibhălāh mĕʾōd</em>, "my whole being is deeply troubled") — <em>nefesh</em> (soul/life/whole self — often the entire person) is deeply dismayed (<em>mĕʾōd</em>: greatly, intensely). <strong>וְאַתָּה יְהוָה עַד-מָתָי</strong> (<em>wĕʾattāh YHWH ʿad-mātay</em>, "But you, O LORD — how long?") — the question breaks off: the sentence is not finished. "How long?" without a verb — the most compressed form of lament, the half-spoken cry. The Hebrew allows the incompleteness to stand as the most natural expression of extremity.</p>',
    "4": '<p><strong>שׁוּבָה יְהוָה חַלְּצָה נַפְשִׁי</strong> (<em>shûbāh YHWH ḥallĕṣāh napshî</em>, "Turn back, O LORD, rescue my life") — <em>shûb</em> (return/turn) is used of God turning his face or attention toward the suppliant. <em>Ḥālaṣ</em> (piel): to strip off, to deliver — the image is of being stripped free from a tight place (related to the root in v5:1 "tight/distress"). <strong>לְמַעַן חַסְדֶּךָ</strong> (<em>lĕmaʿan ḥasdekā</em>, "for the sake of your steadfast love") — the appeal to <em>ḥesed</em> as the motive for rescue: God\'s covenant loyalty demands he act on behalf of his covenant partner.</p>',
    "5": '<p><strong>כִּי אֵין בַּמָּוֶת זִכְרֶךָ</strong> (<em>kî ʾên bammāwet zikrekkā</em>, "for among the dead no one remembers you") — a theologically significant statement of pre-resurrection anthropology: in Sheol (<em>בִּשְׁאוֹל</em>), the dead cannot give thanks or praise. The Psalmist uses the logic of God\'s interest in ongoing worship to argue for rescue: if he dies, God loses a worshiper. This is not a bargaining chip but a recognition that praise belongs to life, not death — a reality the resurrection overturns (see the connections in 1 Cor 15:20).</p>',
    "6": '<p><strong>יָגַעְתִּי בְאַנְחָתִי</strong> (<em>yāgaʿtî bĕʾanḥātî</em>, "I am exhausted with my moaning") — <em>yāgaʿ</em>: weary, fatigued; the moaning itself is exhausting. <strong>אַשְׂחֶה בְכָל-לַיְלָה מִטָּתִי</strong> (<em>ʾaśḥeh bĕkol-layĕlāh miṭṭātî</em>, "every night I drench my bed") — <em>śāḥāh</em>: to float, to swim; the bed is "flooded" with tears. The hyperbole communicates total saturation — no part of sleep unmarked by weeping.</p>',
    "7": '<p><strong>עָשְׁשָׁה מִכַּעַס עֵינִי</strong> (<em>ʿāshĕshāh mikkacʿas ʿênî</em>, "My eye has grown dim from grief") — <em>ʿāshash</em> (poel): to decay, to waste away — the eyes literally deteriorating from prolonged weeping and grief. <em>Kaʿas</em> (grief, vexation, anger): the word can cover both sorrow and the anger of frustration. The physical deterioration (eyes wasting) is a sign of the total impact of the crisis on the body.</p>',
    "8": '<p><strong>סוּרוּ מִמֶּנִּי כָּל-פֹּעֲלֵי אָוֶן</strong> (<em>sûrû mimmennî kol-pōʿălê ʾāwen</em>, "Depart from me, all you who do evil") — the sudden turn from weeping (v1-7) to command (v8-10). The Psalmist now dismisses the wicked as those whose presence is already rendered impossible by the divine response. The confidence of v8 is grounded in v8b: <strong>שָׁמַע יְהוָה קוֹל בִּכְיִי</strong> (<em>shāmaʿ YHWH qôl bikeyî</em>) — "the LORD has heard the sound of my weeping." The weeping was not private; it was heard.</p>',
    "9": '<p><strong>שָׁמַע יְהוָה תְּחִנָּתִי</strong> (<em>shāmaʿ YHWH tĕḥinnātî</em>, "The LORD has heard my supplication") — <em>tĕḥinnāh</em>: a plea for grace/mercy, the verbal noun from <em>ḥānan</em> (be gracious). The LORD has heard and now receives (<em>יִקַּח</em>, <em>yiqqaḥ</em>, imperfect of certainty): the prayer is accepted. The shift from petition (v1-7) to announcement (v8-10) is abrupt — the text does not explain what changed, only that it did. The Psalmist perceives the answer and declares it.</p>',
    "10": '<p><strong>יֵבֹשׁוּ וְיִבָּהֲלוּ מְאֹד</strong> (<em>yêbōshû wĕyibbāhălû mĕʾōd</em>, "shall be ashamed and greatly disturbed") — <em>bûsh</em> (to be ashamed, to be disappointed in one\'s expectations) and <em>bāhal</em> (to be terrified, dismayed — the same word used of the Psalmist\'s bones in v2). The enemies will experience what the Psalmist experienced — reversal. <strong>יָשֻׁבוּ יֵבֹשׁוּ רָגַע</strong> (<em>yāshûbû yêbōshû rāgaʿ</em>, "they shall turn back and be disgraced in an instant") — <em>rāgaʿ</em>: suddenly, in a moment — the swift judgment of the confident Psalmist who has heard God\'s answer.</p>',
  },
  "7": {
    "1": '<p><strong>שִׁגָּיוֹן</strong> (<em>shiggāyôn</em>) — a transliterated genre term appearing only here (the plural <em>shigionoth</em> in Hab 3:1). The derivation is uncertain: possibly from <em>shāgāh</em> (to wander, err, reel) suggesting an irregular, impassioned lyric; or from a cognate Akkadian root for lamentation. The LXX renders it "Psalm." Whatever the genre, it signals a distinctive, passionate form of expression.</p><p>The superscription references "Cush the Benjaminite" — an otherwise unknown figure who apparently slandered David; this personal historical hook gives the corporate lament a specific occasion.</p>',
    "2": '<p><strong>פֶּן-יִטְרֹף כְּאַרְיֵה נַפְשִׁי</strong> (<em>pen-yiṭrōp kĕʾaryēh napshî</em>, "lest they tear my soul apart like a lion") — <em>ṭārap</em>: to tear, to rend (as a lion tears its prey); the verb is used of predatory animals. <em>Nefesh</em> (soul/life/person) as the target — the total person at risk of being torn apart. <strong>וְאֵין מַצִּיל</strong> (<em>wĕʾên maṣṣîl</em>, "with no one to rescue") — the hiphil participle of <em>nāṣal</em>: one who snatches away to safety. The situation is complete vulnerability with no human helper.</p>',
    "3": '<p><strong>יְהוָה אֱלֹהַי אִם-עָשִׂיתִי זֹאת</strong> (<em>YHWH ʾĕlōhay ʾim-ʿāśîtî zōʾt</em>, "O LORD my God, if I have done this") — the conditional oath structure (v3-5) is a form of <em>self-imprecation</em>: "if I am guilty, then let the curse fall on me." The Psalmist invites divine judgment as proof of innocence — a legal procedure akin to a trial by ordeal, but directed to God rather than a human tribunal.</p>',
    "4": '<p><strong>אִם-גָּמַלְתִּי שׁוֹלְמִי רָע</strong> (<em>ʾim-gāmaltî shôlmî rāʿ</em>, "if I have repaid evil to one who was at peace with me") — <em>gāmal</em>: to deal out, to repay; the word also means to wean (as weaning is completing a stage of nurturing). <em>Shôlmî</em>: the one who is at peace/shalom with me, one with whom I have a covenant of friendship. The specific denial is of betrayal of a peaceful relationship — directly relevant if the accusation involves treachery.</p>',
    "5": '<p><strong>יִרְדֹּף אוֹיֵב נַפְשִׁי</strong> (<em>yirdōp ʾôyēb napshî</em>, "let the enemy pursue and overtake me") — the self-imprecation is fully stated: if guilty, let the worst happen. <strong>יִרְמֹס לָאָרֶץ חַיָּתִי</strong> (<em>yirmōs lāʾāreṣ ḥayyātî</em>, "trample my life into the ground") — <em>rāmas</em>: to trample down; <em>ḥayyātî</em> (my life/living self). <strong>כְּבוֹדִי לֶעָפָר יַשְׁכֵּן</strong> (<em>kĕbôdî leʿāpār yashkên</em>, "lay my honor in the dust") — <em>kābôd</em> (glory/honor/weight) reduced to <em>ʿāpār</em> (dust/dirt): the reversal of honor to shame. <em>Selāh</em> marks the weight of the oath.</p>',
    "6": '<p><strong>קוּמָה יְהוָה בְּאַפֶּךָ</strong> (<em>qûmāh YHWH bĕʾappekā</em>, "Rise up, O LORD, in your anger") — the same call as Ps 3:7 but now invoked in the context of established innocence (vv3-5): because David is innocent, the enemy\'s rage is rebellion against the LORD\'s order. <strong>עוּרָה אֵלַי</strong> (<em>ʿûrāh ʾêlay</em>, "rouse yourself") — <em>ʿûr</em>: to awake from sleep, to bestir oneself (used of the divine "sleeping" in Ps 44:23). <strong>מִשְׁפָּט צִוִּיתָ</strong> (<em>mishpāṭ ṣiwwîtāh</em>, "you have decreed judgment") — the judgment is already established by divine command; God is called to execute what he has already decreed.</p>',
    "7": '<p><strong>וַעֲדַת לְאֻמִּים</strong> (<em>waʿădat lĕʾummîm</em>, "the assembly of the peoples") — the image expands from David\'s personal enemies to a cosmic assize: all peoples gathered around the enthroned judge. <strong>עֲלֶיהָ לַמָּרוֹם שׁוּבָה</strong> (<em>ʿălêhā lammārôm shûbāh</em>, "take your seat on high above them") — God is called to ascend to the high seat of judgment above the assembly, not a retreat from the scene but an elevation to the judge\'s bench. The imagery is of a divine court session.</p>',
    "8": '<p><strong>יְהוָה יָדִין עַמִּים</strong> (<em>YHWH yādîn ʿammîm</em>, "The LORD judges the peoples") — the imperfect here is a declaration of God\'s characteristic activity: this is what the LORD does, continually. <strong>שָׁפְטֵנִי יְהוָה כְּצִדְקִי</strong> (<em>shāpĕṭênî YHWH kĕṣidqî</em>, "vindicate me, O LORD, according to my righteousness") — the appeal to <em>ṣedeq</em> (righteousness) in the forensic sense: judge my case on the merits of my actual conduct, not the accusations of enemies. <em>Ûtĕmimmî</em> (my integrity/wholeness) — <em>tōm</em>: completeness, uprightness without a crack or hidden defect.</p>',
    "9": '<p><strong>בֹּחֵן לִבּוֹת וּכְלָיוֹת</strong> (<em>bōḥên libbôt ûkĕlāyôt</em>, "the righteous God searches hearts and minds") — <em>bāḥan</em>: to test, assay (as metal is tested); the participle expresses characteristic ongoing action. <em>Libbôt</em> (hearts — plural of <em>lēb</em>) = the organ of thought, will, intention; <em>kĕlāyôt</em> (kidneys) = the deepest seat of emotion and secret purpose. Together they indicate the total interior life — nothing hidden from this divine search. Rev 2:23 applies this directly to Christ: "I am he who searches minds and hearts."</p>',
    "10": '<p><strong>מָגִנִּי עַל-אֱלֹהִים</strong> (<em>māginnî ʿal-ʾĕlōhîm</em>, "My shield is God, the Most High") — <em>māgên</em> (small handheld shield, as in Ps 3:3) with the proposition <em>ʿal</em> (upon/above/through): the shield that is upon me comes from God. <strong>מוֹשִׁיעַ יִשְׁרֵי-לֵב</strong> (<em>môshîaʿ yishĕrê-lēb</em>, "who saves those who are upright in heart") — <em>yāshar</em>: straight, right; those whose heart is without crookedness. The divine savior (<em>môshîaʿ</em>) is the one who rescues the innocent, consistent with the appeal of vv3-8.</p>',
    "11": '<p><strong>אֵל שׁוֹפֵט צַדִּיק</strong> (<em>ʾêl shôpêṭ ṣaddîq</em>, "God is a righteous judge") — three predicates: <em>ʾêl</em> (God/El), <em>shôpêṭ</em> (participle: continuously judging), <em>ṣaddîq</em> (righteous). The participle is important: not a future judgment only but a present, ongoing activity. <strong>וְאֵל זֹעֵם בְּכָל-יוֹם</strong> (<em>wĕʾêl zōʿêm bĕkol-yôm</em>, "a God who expresses indignation every day") — <em>zāʿam</em>: to be indignant, to be enraged; the participle again indicates habitual, ongoing activity. Divine anger is not periodic but continuous in response to ongoing wickedness — not stored up for an eventual reckoning but always present.</p>',
    "12": '<p><strong>אִם-לֹא יָשׁוּב חַרְבּוֹ יִלְטוֹשׁ</strong> (<em>ʾim-lōʾ yāshûb ḥarbô yilṭôsh</em>, "If a man does not repent, God will sharpen his sword") — the "if" is conditional on continued unrepentance: <em>shûb</em> (to turn/repent) is the condition. <em>Lāṭash</em>: to sharpen, to whet (as a sword is sharpened on a stone). God is depicted as an armed judge preparing weapons — the imagery of divine warrior preparing for battle against the unrepentant. <strong>קַשְׁתּוֹ דָּרַךְ וַיְכוֹנְנֶהָ</strong> — "bent his bow and strung it" — two completed actions (perfect): the bow is already bent and made ready.</p>',
    "13": '<p><strong>לוֹ הֵכִין כְּלֵי-מָוֶת</strong> (<em>lô hêkîn kĕlê-māwet</em>, "He has prepared deadly weapons against the persecutors") — <em>hêkîn</em> (hiphil of <em>kûn</em>): to establish, to make firm/ready. The "weapons of death" are prepared specifically for the persecutors. <strong>חִצָּיו לַדֹּלְקִים יִפְעַל</strong> (<em>ḥiṣṣāyw laddōlĕqîm yipʿal</em>, "his arrows will be fiery shafts") — <em>dālaq</em>: to pursue hotly, to inflame; those who hotly pursue the Psalmist become the targets of flaming arrows. The imagery picks up the ancient Canaanite war-god iconography while applying it to the LORD\'s justice.</p>',
    "14": '<p><strong>הִנֵּה יְחַבֶּל-אָוֶן</strong> (<em>hinnēh yĕḥabbel-ʾāwen</em>, "Look: the wicked person conceives evil") — three birth-metaphors for the production of evil: conceiving (<em>yĕḥabbel</em>, piel of <em>ḥābal</em>: to be in birth-pangs, to conceive), becoming pregnant (<em>הָרָה</em>, <em>hārāh</em>: pregnant), giving birth (<em>וְיָלַד</em>, <em>wĕyālad</em>: to bear/give birth). Evil is not accidental but the product of a deliberate generative process — it is what the wicked person produces when they are most fully themselves.</p>',
    "15": '<p><strong>בּוֹר כָּרָה וַיַּחְפְּרֵהוּ</strong> (<em>bôr kārāh wayyaḥpĕrêhû</em>, "He dug a pit, made it deep") — two verbs for the excavation work: <em>kārāh</em> (to dig) and <em>ḥāpar</em> (to dig/search): he dug and then deepened it. The pit is the trap set for another — but <strong>וַיִּפֹּל בְּשַׁחַת יִפְעָל</strong> (<em>wayyippōl bĕshaḥat yipʿal</em>): "and fell into the very pit he made." The self-entrapment is the theme of vv15-16 — the retributive principle built into the moral order: evil returns on its maker.</p>',
    "16": '<p><strong>יָשׁוּב עֲמָלוֹ בְרֹאשׁוֹ</strong> (<em>yāshûb ʿămālô bĕrōʾshô</em>, "His mischief comes back on his own head") — <em>ʿāmāl</em> (trouble, mischief, toil — the laborious effort put into evil); it "returns" (<em>yāshûb</em>) to the head — the top of the one who worked it. <strong>עַל-קָדְקֳדוֹ חֲמָסוֹ יֵרֵד</strong> (<em>ʿal-qodqodô ḥāmāsô yêrêd</em>, "his violence falls down on his own skull") — <em>ḥāmās</em> (violence) descending on the <em>qodqōd</em> (skull/crown of the head). The image is of the violence thrown upward returning on its thrower.</p>',
    "17": '<p><strong>אוֹדֶה יְהוָה כְּצִדְקוֹ</strong> (<em>ʾôdeh YHWH kĕṣidqô</em>, "I will give thanks to the LORD for his righteousness") — the psalm closes where it began: God\'s righteousness. The same <em>ṣedeq</em> appealed to in v8 (vindicate me according to my righteousness) is now the content of praise: God\'s righteousness is itself the reason for thanksgiving. <strong>אֲזַמְּרָה שֵׁם-יְהוָה עֶלְיוֹן</strong> (<em>ʾăzammĕrāh shêm-YHWH ʿelyôn</em>) — "sing praise to the name of the LORD Most High" — <em>ʿelyôn</em> (Most High, the Canaanite divine title applied to the LORD) completes the psalm with the highest divine title, appropriate for the cosmic judge of vv7-8.</p>',
  },
  "8": {
    "1": '<p><strong>יְהוָה אֲדֹנֵינוּ</strong> (<em>YHWH ʾădōnênû</em>, "O LORD our Lord") — a compressed theologoumenon: the personal covenant name YHWH combined with the sovereign title <em>ʾādôn</em> (master/lord) with the first-person plural suffix: our sovereign. The doubled address — YHWH as personal name, ʾAdônênû as title — appears identically at the psalm\'s close (v9), forming an <em>inclusio</em> that brackets the entire meditation.</p><p><strong>אֲשֶׁר-תְּנָה הוֹדְךָ עַל-הַשָּׁמָיִם</strong> (<em>ʾăsher-tĕnāh hôdĕkā ʿal-hashāmāyim</em>, "You have placed your glory above the heavens") — <em>hôd</em> (splendor/majesty/glory) exceeding even the heavens in scope. The same word used of royal majesty (1 Chr 29:25) and the garment of divine splendor (Ps 104:1). The glory that cannot be contained in the heavens (1 Kgs 8:27) is the overflow of the Creator\'s nature.</p>',
    "2": '<p><strong>מִפִּי עוֹלְלִים וְיֹנְקִים</strong> (<em>mippî ʿôlĕlîm wĕyōnĕqîm</em>, "From the mouths of children and nursing infants") — <em>ʿôlĕlîm</em> (children, those who glean or play) and <em>yōnĕqîm</em> (nursing infants, from <em>yānaq</em>, to suck): the most dependent and inarticulate of human beings. <strong>יִסַּדְתָּ עֹז</strong> (<em>yissadtā ʿōz</em>, "you have ordained praise") — the key translation decision: <em>ʿōz</em> means "strength/fortress/might" but the LXX rendered it αἶνον (praise), and that is how Jesus cites it in Matt 21:16 ("from the mouth of children you have prepared praise"). The MKT follows the LXX interpretation; the Hebrew is genuinely ambiguous — "you have established strength/praise" through the weakest voices.</p>',
    "3": '<p><strong>מַעֲשֵׂה אֶצְבְּעֹתֶיךָ</strong> (<em>maʿăśê ʾeṣbĕʿōtêkā</em>, "the work of your fingers") — <em>ʾeṣbaʿ</em> (finger): the delicate, precise digit rather than the hand. Ps 19:1 uses "hands" for the heavens; here Psalm 8:3 uses "fingers" for the moon and stars — the fine-detail work of precise craftsmanship, as if the stars were set in place individually with fingertips. The cosmos as divine handiwork of unimaginable precision and care.</p>',
    "5": '<p><strong>וַתְּחַסְּרֵהוּ מְּעַט מֵאֱלֹהִים</strong> (<em>watĕḥassĕrêhû mĕʿaṭ mêʾĕlōhîm</em>, "Yet you have made him just a little lower than the heavenly beings") — the central interpretive crux: is <em>ʾĕlōhîm</em> God himself, or divine/heavenly beings (angels)? All three options have ancient support: the LXX reads ἀγγέλους (angels), which Heb 2:7 follows and applies to Christ. If the MT means God, the gap between humanity and the creator is rendered almost infinitesimal — a remarkable statement of human dignity. The MKT "heavenly beings" preserves the ambiguity while leaning toward the LXX/Hebrews reading.</p><p><strong>וְכָבוֹד וְהָדָר תְּעַטְּרֵהוּ</strong> (<em>wĕkābôd wĕhādār tĕʿaṭṭĕrêhû</em>, "crowned him with glory and honor") — the same royal vocabulary used of the Davidic king (Ps 21:5) applied to humanity as a whole. The crown (<em>ʿāṭar</em>) is the royal coronation — humanity as the crown-bearing representative of the Creator in the created order.</p>',
    "6": '<p><strong>תַּמְשִׁילֵהוּ בְּמַעֲשֵׂי יָדֶיךָ</strong> (<em>tamshîlêhû bĕmaʿăśê yādêkā</em>, "You have given him dominion over the works of your hands") — <em>māshal</em> (hiphil: to cause to rule/have dominion); the same verb root that underlies "ruling" in Gen 1:26-28. Humanity is placed in the position of ruling <em>over</em> what God\'s hands made — a profound delegation of creative authority. <strong>כֹּל שַׁתָּה תַחַת-רַגְלָיו</strong> (<em>kōl shattāh taḥat-raglāyw</em>, "you have placed everything under his feet") — "all" (<em>kōl</em>) without qualification; "under his feet" (<em>taḥat raglāyw</em>) is the posture of subjects before a king, enemies before a conqueror. Heb 2:8 acknowledges that "we do not yet see everything subjected to him" — the psalm describes the eschatological reality that Christ will fully enact.</p>',
    "7": '<p><strong>צֹנֶה וַאֲלָפִים כֻּלָּם</strong> (<em>ṣōneh waʾălāpîm kullām</em>, "all sheep and cattle") — the specification of "all sheep and cattle" begins the inventory of the creation under human dominion, descending from domesticated animals to wild, then to the sky, then the sea. The comprehensiveness matches Gen 1:28\'s categories. The verse has no syntactic complexity — it is a list, and the simplicity amplifies the sweep of the grant.</p>',
    "8": '<p><strong>צִפּוֹר שָׁמַיִם וּדְגֵי הַיָּם</strong> (<em>ṣippôr shāmayim ûdĕgê hayyām</em>, "the birds of the sky and the fish of the sea") — the inventory now covers the three realms: land (v7), sky, and sea. <strong>עֹבֵר אָרְחוֹת יַמִּים</strong> (<em>ʿōbêr ʾorĕḥôt yammîm</em>, "whatever moves along the ocean\'s currents") — the participle <em>ʿōbêr</em> (moving along) and the plural <em>ʾorĕḥôt</em> (paths/currents) of <em>yammîm</em> (seas): whatever passes through the lanes of the sea. The underwater paths suggest the orderly structure even of ocean currents — the cosmos is not chaotic but has paths. All creatures in all domains are named as subject to the human delegate.</p>',
    "9": '<p>The verbal repetition of v1 — <strong>יְהוָה אֲדֹנֵינוּ מָה-אַדִּיר שִׁמְךָ בְּכָל-הָאָרֶץ</strong> — closes the <em>inclusio</em>. The meditation moves from praise of the Name (v1), through the marvel of human dignity within the creation (vv2-8), back to praise of the Name (v9). The theological movement is: the majestic Creator has made frail humans (<em>ʾĕnôsh</em>, v4) as his ruling representatives — a paradox that resolves only in the one who is fully both: the Son of Man who is also Lord of all.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    for ch in range(1, 9):
        print(f"  ch{ch}: {len(existing.get(str(ch), {}))} verses")
    print('Psalms 1-8 mkt-original written.')

if __name__ == '__main__':
    main()
